28.     {
29.         _logger.LogInformation("Loading training data from {Path}", _dataPath);
30. 
31.         var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
32.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
33. 
34.         var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
35. 
