1. using Microsoft.AspNetCore.Mvc;
2. using Microsoft.Extensions.ML;
3. using TicketClassifier.Models;
4. using TicketClassifier.Services;
5. 
6. namespace TicketClassifier.Controllers;
7. 
8. [ApiController]
9. [Route("api/[controller]")]
10. public sealed class TicketController : ControllerBase
11. {
12.     private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
13.     private readonly LabelMapping _labelMapping;
14. 
15.     public TicketController(
16.         PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
17.         LabelMapping labelMapping)
18.     {
19.         _predictionPool = predictionPool;
20.         _labelMapping = labelMapping;
21.     }
22. 
23.     [HttpPost("classify")]
24.     public ActionResult<ClassifyResponse> Classify([FromBody] ClassifyRequest request)
25.     {
26.         if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
27.             return BadRequest("Subject and Description are required.");
28. 
29.         if (request.Priority is < 1 or > 3)
30.             return BadRequest("Priority must be between 1 and 3.");
31. 
32.         var input = new TicketInput
33.         {
34.             Subject = request.Subject,
35.             Description = request.Description,
36.             Priority = request.Priority,
37.         };
38. 
39.         var prediction = _predictionPool.Predict(input);
40. 
41.         var confidences = _labelMapping.Labels
42.             .Zip(prediction.Score, (cat, score) => new { cat, score })
43.             .OrderByDescending(x => x.score)
44.             .ToDictionary(x => x.cat, x => Math.Round(x.score, 4));
45. 
46.         return Ok(new ClassifyResponse
47.         {
48.             PredictedCategory = prediction.PredictedCategory,
49.             Confidence = confidences,
50.         });
51.     }
52. }
53. 
54. public sealed class ClassifyRequest
55. {
56.     public string Subject { get; set; } = string.Empty;
57.     public string Description { get; set; } = string.Empty;
58.     public int Priority { get; set; }
59. }
60. 
61. public sealed class ClassifyResponse
62. {
63.     public string PredictedCategory { get; set; } = string.Empty;
64.     public Dictionary<string, double> Confidence { get; set; } = new();
65. }
